@startuml
title Combat Subsystem Class Diagram

skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam class {
  BackgroundColor #F2F2F2
  BorderColor #333333
}
skinparam note {
  BackgroundColor #E6E6E6
  BorderColor #333333
}

class CombatManager <<C>> {
}

class Player <<C>> {
}

class Combat <<C>> {
  Combatants allies
  Combatants enemies
  Inventory reward
  Move playerMove
  Move npcMove
  --
  turn()
}

class Move <<C>> {
  String name
  int blockPercent
  double damage
  double healing
}

class Combatants <<C>> {
}

class Inventory <<C>> {
}

class Entity <<C>> {
}

CombatManager o-- "0..*" Player
CombatManager *-- Combat

Combat *-- "2" Move
Combat o-- "2" Combatants
Combat *-- "1" Inventory

Combatants o-- "0..*" Entity

note bottom
Authored: Mason Fabel
Reviewed: Casey Blair

External Classes: Entity, Inventory, Player
end note

@enduml
